func (bl *BeeLogger) startLogger() {
	gameOver := false
	for {
		select {
		case bm, ok := <-bl.msgChan:

			if ok {
				bl.writeToLoggers(bm)
				logMsgPool.Put(bm)
			}
		case <-bl.closeChan:
			bl.flush()
			for _, l := range bl.outputs {
				l.Destroy()
			}
			bl.outputs = nil
			gameOver = true
			bl.wg.Done()
		case <-bl.flushChan:
			bl.flush()
			bl.wg.Done()
		}
		if gameOver {
			break
		}
	}
}
